import React from "react"
import Select from 'react-select'
import { properties } from '../../properties/properties.js'
import querystring from 'query-string'
import { Chart as ChartJS, registerables } from 'chart.js';
import { Bar } from 'react-chartjs-2'

ChartJS.register(...registerables);

class Report extends React.Component {


    constructor(props) {
        super(props);
        this.state = {
            results: [], screen: 0, selectedYear: [], selectedProgram: [], selectedCategory: [], questionOptions: [], selectedQuestion: [], chartResultData: [], selectedType: []
        };
    }


    handleBack = () => {
      this.setState({screen: 1})
    }

    handleYearChange = (selectedOptions) => {
        this.setState({selectedYear: selectedOptions})
      }

      handleProgramChange = (selectedOptions) => {
        this.setState({selectedProgram: selectedOptions})
      }

      handleCategoryChange = (selectedOptions) => {
        this.setState({selectedCategory: selectedOptions})
        this.setState({selectedQuestion: []})
//this.state.questionOptions
        var questionOptions = []
        for (var index in selectedOptions) {
          var option = selectedOptions[index]
          var filter = this.state.results.category.filter(rec => rec.category == option.value)
          if (filter.length > 0) {
            for (var index2 in filter[0].questions) {
              questionOptions.push({value: filter[0].questions[index2].question, label: filter[0].questions[index2].question})
            }

          }

        }
        this.setState({questionOptions: questionOptions})
        //console.log(questionOptions)
        //{value: rec.category, label: rec.category}

      }


      handleQuestionChange = (selectedOptions) => {
        this.setState({selectedQuestion: selectedOptions})
      }

      handleTypeChange = (selectedOptions) => {
        this.setState({selectedType: selectedOptions})
      }


      handleSubmit = () => {
      this.setState({screen: 0});

      let headers = new Headers();

      headers.append('Content-Type', 'application/json');
      headers.append('Accept', 'application/json');


      var backUrl = properties.backend + `getEducationData`
      fetch(backUrl, {
        "method": "POST",
        headers: headers,
        body: JSON.stringify({year: this.state.selectedYear, category: this.state.selectedCategory, program: this.state.selectedProgram, type: this.state.selectedType, question: this.state.selectedQuestion})

      })
      .then(response => response.json())
      .then(response => {
        this.setState({chartResultData: response})
        this.setState({screen: 2})
        //this.setState({selectedYear: []})
        //this.setState({selectedCategory: []})
        //this.setState({selectedProgram: []})
      })
      .catch(err => {
        console.log(err);
      });

    }

      componentDidMount() {



        this.setState({screen: 0})

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        fetch(properties.backend + `educationOption`, {
            "method": "GET",
            headers: headers
          })
          .then(response => response.json())
          .then(response => {

            this.setState({results: response})
            this.setState({screen: 1})


          })
          .catch(err => {
            console.log(err);
          });

      }






          render() {


            var header = "Loading ..."
            var content = []

